   122→function fork(modulePath, args = [], options) {
   123→  modulePath = getValidatedPath(modulePath, 'modulePath');
   124→
   125→  // Get options and args arguments.
   126→  let execArgv;
   127→
   128→  if (args == null) {
   129→    args = [];
   130→  } else if (typeof args === 'object' && !ArrayIsArray(args)) {
   131→    options = args;
   132→    args = [];
   133→  } else {
   134→    validateArray(args, 'args');
   135→  }
   136→
   137→  if (options != null) {
   138→    validateObject(options, 'options');
   139→  }
   140→  options = { __proto__: null, ...options, shell: false };
   141→  options.execPath ||= process.execPath;
   142→  validateArgumentNullCheck(options.execPath, 'options.execPath');
   143→
   144→  // Prepare arguments for fork:
   145→  execArgv = options.execArgv || process.execArgv;
   146→  validateArgumentsNullCheck(execArgv, 'options.execArgv');
   147→
   148→  if (execArgv === process.execArgv && process._eval != null) {
   149→    const index = ArrayPrototypeLastIndexOf(execArgv, process._eval);
   150→    if (index > 0) {
   151→      // Remove the -e switch to avoid fork bombing ourselves.
   152→      execArgv = ArrayPrototypeSlice(execArgv);
   153→      ArrayPrototypeSplice(execArgv, index - 1, 2);
   154→    }
   155→  }
   156→
   157→  args = [...execArgv, modulePath, ...args];
   158→
   159→  if (typeof options.stdio === 'string') {
   160→    options.stdio = stdioStringToArray(options.stdio, 'ipc');
   161→  } else if (!ArrayIsArray(options.stdio)) {
   162→    // Use a separate fd=3 for the IPC channel. Inherit stdin, stdout,
   163→    // and stderr from the parent if silent isn't set.
