   238→const customPromiseExecFunction = (orig) => {
   239→  return (...args) => {
   240→    const { promise, resolve, reject } = PromiseWithResolvers();
   241→
   242→    promise.child = orig(...args, (err, stdout, stderr) => {
   243→      if (err !== null) {
   244→        err.stdout = stdout;
   245→        err.stderr = stderr;
   246→        reject(err);
   247→      } else {
   248→        resolve({ stdout, stderr });
   249→      }
   250→    });
   251→
   252→    return promise;
   253→  };
   254→};
