   262→function normalizeExecFileArgs(file, args, options, callback) {
   263→  if (ArrayIsArray(args)) {
   264→    args = ArrayPrototypeSlice(args);
   265→  } else if (args != null && typeof args === 'object') {
   266→    callback = options;
   267→    options = args;
   268→    args = null;
   269→  } else if (typeof args === 'function') {
   270→    callback = args;
   271→    options = null;
   272→    args = null;
   273→  }
   274→
   275→  args ??= [];
   276→
   277→  if (typeof options === 'function') {
   278→    callback = options;
   279→  } else if (options != null) {
   280→    validateObject(options, 'options');
   281→  }
   282→
   283→  options ??= kEmptyObject;
   284→
   285→  if (callback != null) {
   286→    validateFunction(callback, 'callback');
   287→  }
