   298→/**
   299→ * Spawns the specified file as a shell.
   300→ * @param {string} file
   301→ * @param {string[]} [args]
   302→ * @param {{
   303→ *   cwd?: string | URL;
   304→ *   env?: Record<string, string>;
   305→ *   encoding?: string;
   306→ *   timeout?: number;
   307→ *   maxBuffer?: number;
   308→ *   killSignal?: string | number;
   309→ *   uid?: number;
   310→ *   gid?: number;
   311→ *   windowsHide?: boolean;
   312→ *   windowsVerbatimArguments?: boolean;
   313→ *   shell?: boolean | string;
   314→ *   signal?: AbortSignal;
   315→ *   }} [options]
   316→ * @param {(
   317→ *   error?: Error,
   318→ *   stdout?: string | Buffer,
   319→ *   stderr?: string | Buffer
   320→ *   ) => any} [callback]
   321→ * @returns {ChildProcess}
   322→ */
