   324→  ({ file, args, options, callback } = normalizeExecFileArgs(file, args, options, callback));
   325→
   326→  options = {
   327→    __proto__: null,
   328→    encoding: 'utf8',
   329→    timeout: 0,
   330→    maxBuffer: MAX_BUFFER,
   331→    killSignal: 'SIGTERM',
   332→    cwd: null,
   333→    env: null,
   334→    shell: false,
   335→    ...options,
   336→  };
