   674→    const sawKey = new SafeSet();
   675→    envKeys = ArrayPrototypeFilter(
   676→      ArrayPrototypeSort(envKeys),
   677→      (key) => {
   678→        const uppercaseKey = StringPrototypeToUpperCase(key);
   679→        if (sawKey.has(uppercaseKey)) {
   680→          return false;
   681→        }
   682→        sawKey.add(uppercaseKey);
   683→        return true;
   684→      },
   685→    );
   686→  }
   687→
   688→  for (const key of envKeys) {
   689→    const value = env[key];
   690→    if (value !== undefined) {
   691→      validateArgumentNullCheck(key, `options.env['${key}']`);
   692→      validateArgumentNullCheck(value, `options.env['${key}']`);
   693→      ArrayPrototypePush(envPairs, `${key}=${value}`);
   694→    }
   695→  }
   696→
   697→  return {
   698→    // Make a shallow copy so we don't clobber the user's options object.
   699→    __proto__: null,
   700→    ...options,
   701→    args,
   702→    cwd,
   703→    detached: !!options.detached,
   704→    envPairs,
   705→    file,
   706→    windowsHide: !!options.windowsHide,
   707→    windowsVerbatimArguments: !!windowsVerbatimArguments,
   708→  };
   709→}
   710→
   711→function abortChildProcess(child, killSignal, reason) {
   712→  if (!child)
   713→    return;
   714→  try {
   715→    if (child.kill(killSignal)) {
   716→      child.emit('error', new AbortError(undefined, { cause: reason }));
   717→    }
   718→  } catch (err) {
   719→    child.emit('error', err);
   720→  }
   721→}
   722→
   723→/**
   724→ * Spawns a new process using the given `file`.
   725→ * @param {string} file
   726→ * @param {string[]} [args]
   727→ * @param {{
   728→ *   cwd?: string | URL;
   729→ *   env?: Record<string, string>;
   730→ *   argv0?: string;
   731→ *   stdio?: Array | string;
   732→ *   detached?: boolean;
   733→ *   uid?: number;
   734→ *   gid?: number;
   735→ *   serialization?: string;
   736→ *   shell?: boolean | string;
   737→ *   windowsVerbatimArguments?: boolean;
   738→ *   windowsHide?: boolean;
   739→ *   signal?: AbortSignal;
   740→ *   timeout?: number;
   741→ *   killSignal?: string | number;
   742→ *   }} [options]
   743→ * @returns {ChildProcess}
   744→ */
   745→function spawn(file, args, options) {
   746→  options = normalizeSpawnArguments(file, args, options);
   747→  validateTimeout(options.timeout);
   748→  validateAbortSignal(options.signal, 'options.signal');
   749→  const killSignal = sanitizeKillSignal(options.killSignal);
   750→  const child = new ChildProcess();
   751→
   752→  debug('spawn', options);
   753→  child.spawn(options);
   754→
   755→  if (options.timeout > 0) {
   756→    let timeoutId = setTimeout(() => {
   757→      if (timeoutId) {
   758→        try {
   759→          child.kill(killSignal);
   760→        } catch (err) {
   761→          child.emit('error', err);
   762→        }
   763→        timeoutId = null;
   764→      }
   765→    }, options.timeout);
   766→
   767→    child.once('exit', () => {
   768→      if (timeoutId) {
   769→        clearTimeout(timeoutId);
   770→        timeoutId = null;
   771→      }
   772→    });
   773→  }
   774→
   775→  if (options.signal) {
   776→    const signal = options.signal;
   777→    if (signal.aborted) {
   778→      process.nextTick(onAbortListener);
   779→    } else {
   780→      addAbortListener ??= require('internal/events/abort_listener').addAbortListener;
   781→      const disposable = addAbortListener(signal, onAbortListener);
   782→      child.once('exit', disposable[SymbolDispose]);
   783→    }
   784→
   785→    function onAbortListener() {
   786→      abortChildProcess(child, killSignal, options.signal.reason);
   787→    }
   788→  }
   789→
   790→  return child;
   791→}
   792→
   793→/**
   794→ * Spawns a new process synchronously using the given `file`.
   795→ * @param {string} file
   796→ * @param {string[]} [args]
   797→ * @param {{
   798→ *   cwd?: string | URL;
   799→ *   input?: string | Buffer | TypedArray | DataView;
   800→ *   argv0?: string;
   801→ *   stdio?: string | Array;
   802→ *   env?: Record<string, string>;
   803→ *   uid?: number;
   804→ *   gid?: number;
   805→ *   timeout?: number;
   806→ *   killSignal?: string | number;
   807→ *   maxBuffer?: number;
   808→ *   encoding?: string;
   809→ *   shell?: boolean | string;
   810→ *   windowsVerbatimArguments?: boolean;
   811→ *   windowsHide?: boolean;
   812→ *   }} [options]
   813→ * @returns {{
   814→ *   pid: number;
   815→ *   output: Array;
   816→ *   stdout: Buffer | string;
   817→ *   stderr: Buffer | string;
   818→ *   status: number | null;
   819→ *   signal: string | null;
   820→ *   error: Error;
   821→ *   }}
   822→ */
   823→function spawnSync(file, args, options) {
   824→  options = {
   825→    __proto__: null,
   826→    maxBuffer: MAX_BUFFER,
   827→    ...normalizeSpawnArguments(file, args, options),
   828→  };
   829→
   830→  debug('spawnSync', options);
   831→
   832→  // Validate the timeout, if present.
   833→  validateTimeout(options.timeout);
   834→
   835→  // Validate maxBuffer, if present.
   836→  validateMaxBuffer(options.maxBuffer);
   837→
   838→  // Validate and translate the kill signal, if present.
   839→  options.killSignal = sanitizeKillSignal(options.killSignal);
   840→
   841→  options.stdio = getValidStdio(options.stdio || 'pipe', true).stdio;
   842→
   843→  if (options.input) {
   844→    const stdin = options.stdio[0] = { ...options.stdio[0] };
   845→    stdin.input = options.input;
   846→  }
   847→
   848→  // We may want to pass data in on any given fd, ensure it is a valid buffer
   849→  for (let i = 0; i < options.stdio.length; i++) {
   850→    const input = options.stdio[i]?.input;
   851→    if (input != null) {
   852→      const pipe = options.stdio[i] = { ...options.stdio[i] };
   853→      if (isArrayBufferView(input)) {
   854→        pipe.input = input;
   855→      } else if (typeof input === 'string') {
   856→        pipe.input = Buffer.from(input, options.encoding);
   857→      } else {
   858→        throw new ERR_INVALID_ARG_TYPE(`options.stdio[${i}]`,
   859→                                       ['Buffer',
   860→                                        'TypedArray',
   861→                                        'DataView',
   862→                                        'string'],
   863→                                       input);
   864→      }
   865→    }
   866→  }
   867→
   868→  return child_process.spawnSync(options);
   869→}
   870→
   871→
   872→function checkExecSyncError(ret, args, cmd) {
   873→  let err;
   874→  if (ret.error) {
   875→    err = ret.error;
   876→    ObjectAssign(err, ret);
   877→  } else if (ret.status !== 0) {
   878→    let msg = 'Command failed: ';
   879→    msg += cmd || ArrayPrototypeJoin(args, ' ');
   880→    if (ret.stderr && ret.stderr.length > 0)
   881→      msg += `\n${ret.stderr.toString()}`;
   882→    err = genericNodeError(msg, ret);
   883→  }
   884→  return err;
   885→}
   886→
   887→/**
   888→ * Spawns a file as a shell synchronously.
   889→ * @param {string} file
   890→ * @param {string[]} [args]
   891→ * @param {{
   892→ *   cwd?: string | URL;
   893→ *   input?: string | Buffer | TypedArray | DataView;
   894→ *   stdio?: string | Array;
   895→ *   env?: Record<string, string>;
   896→ *   uid?: number;
   897→ *   gid?: number;
   898→ *   timeout?: number;
   899→ *   killSignal?: string | number;
   900→ *   maxBuffer?: number;
   901→ *   encoding?: string;
   902→ *   windowsHide?: boolean;
   903→ *   shell?: boolean | string;
   904→ *   }} [options]
   905→ * @returns {Buffer | string}
   906→ */
   907→function execFileSync(file, args, options) {
   908→  ({ file, args, options } = normalizeExecFileArgs(file, args, options));
   909→
   910→  const inheritStderr = !options.stdio;
   911→  const ret = spawnSync(file, args, options);
   912→
   913→  if (inheritStderr && ret.stderr)
   914→    process.stderr.write(ret.stderr);
   915→
   916→  const errArgs = [options.argv0 || file];
   917→  ArrayPrototypePushApply(errArgs, args);
   918→  const err = checkExecSyncError(ret, errArgs);
   919→
   920→  if (err)
   921→    throw err;
   922→
   923→  return ret.stdout;
   924→}
   925→
   926→/**
   927→ * Spawns a shell executing the given `command` synchronously.
   928→ * @param {string} command
   929→ * @param {{
   930→ *   cwd?: string | URL;
   931→ *   input?: string | Buffer | TypedArray | DataView;
   932→ *   stdio?: string | Array;
   933→ *   env?: Record<string, string>;
   934→ *   shell?: string;
   935→ *   uid?: number;
   936→ *   gid?: number;
   937→ *   timeout?: number;
   938→ *   killSignal?: string | number;
   939→ *   maxBuffer?: number;
   940→ *   encoding?: string;
   941→ *   windowsHide?: boolean;
   942→ *   }} [options]
   943→ * @returns {Buffer | string}
   944→ */
   945→function execSync(command, options) {
   946→  const opts = normalizeExecArgs(command, options, null);
   947→  const inheritStderr = !opts.options.stdio;
   948→
   949→  const ret = spawnSync(opts.file, opts.options);
   950→
   951→  if (inheritStderr && ret.stderr)
   952→    process.stderr.write(ret.stderr);
   953→
   954→  const err = checkExecSyncError(ret, undefined, command);
   955→
   956→  if (err)
   957→    throw err;
   958→
   959→  return ret.stdout;
   960→}
   961→
   962→
   963→function validateArgumentNullCheck(arg, propName) {
   964→  if (typeof arg === 'string' && StringPrototypeIncludes(arg, '\u0000')) {
   965→    throw new ERR_INVALID_ARG_VALUE(propName, arg, 'must be a string without null bytes');
   966→  }
   967→}
   968→
   969→
   970→function validateArgumentsNullCheck(args, propName) {
   971→  for (let i = 0; i < args.length; ++i) {
   972→    validateArgumentNullCheck(args[i], `${propName}[${i}]`);
   973→  }
   974→}
   975→
   976→
   977→function validateTimeout(timeout) {
   978→  if (timeout != null && !(NumberIsInteger(timeout) && timeout >= 0)) {
   979→    throw new ERR_OUT_OF_RANGE('timeout', 'an unsigned integer', timeout);
   980→  }
   981→}
   982→
   983→
   984→function validateMaxBuffer(maxBuffer) {
   985→  if (maxBuffer != null && !(typeof maxBuffer === 'number' && maxBuffer >= 0)) {
   986→    throw new ERR_OUT_OF_RANGE('options.maxBuffer',
   987→                               'a positive number',
   988→                               maxBuffer);
   989→  }
   990→}
   991→
   992→
   993→function sanitizeKillSignal(killSignal) {
   994→  if (typeof killSignal === 'string' || typeof killSignal === 'number') {
   995→    return convertToValidSignal(killSignal);
   996→  } else if (killSignal != null) {
   997→    throw new ERR_INVALID_ARG_TYPE('options.killSignal',
   998→                                   ['string', 'number'],
   999→                                   killSignal);
  1000→  }
  1001→}
  1002→
  1003→module.exports = {
  1004→  _forkChild,
  1005→  ChildProcess,
  1006→  exec,
  1007→  execFile,
  1008→  execFileSync,
  1009→  execSync,
  1010→  fork,
  1011→  spawn,
  1012→  spawnSync,
  1013→};
  1014→

