1005→Maybe<int> SyncProcessRunner::CopyJsString(Local<Value> js_value,
  1006→                                           const char** target) {
  1007→  Isolate* isolate = env()->isolate();
  1008→  Local<String> js_string;
  1009→  size_t size, written;
  1010→  char* buffer;
  1011→
  1012→  if (js_value->IsString())
  1013→    js_string = js_value.As<String>();
  1014→  else if (!js_value->ToString(env()->isolate()->GetCurrentContext())
  1015→                .ToLocal(&js_string))
  1016→    return Nothing<int>();
  1017→
  1018→  // Include space for null terminator byte.
  1019→  if (!StringBytes::StorageSize(isolate, js_string, UTF8).To(&size))
  1020→    return Nothing<int>();
  1021→  size += 1;
  1022→
  1023→  buffer = new char[size];
  1024→
  1025→  written = StringBytes::Write(isolate, buffer, -1, js_string, UTF8);
  1026→  buffer[written] = '\0';
  1027→
  1028→  *target = buffer;
  1029→  return Just(0);
  1030→}
