  1044→  js_array = js_value.As<Array>()->Clone().As<Array>();
  1045→  length = js_array->Length();
  1046→  data_size = 0;
  1047→
  1048→  // Index has a pointer to every string element, plus one more for a final
  1049→  // null pointer.
  1050→  list_size = (length + 1) * sizeof *list;
  1051→
  1052→  // Convert all array elements to string. Modify the js object itself if
  1053→  // needed - it's okay since we cloned the original object. Also compute the
  1054→  // length of all strings, including room for a null terminator after every
  1055→  // string. Align strings to cache lines.
  1056→  for (uint32_t i = 0; i < length; i++) {
  1057→    auto value = js_array->Get(context, i).ToLocalChecked();
  1058→
  1059→    if (!value->IsString()) {
  1060→      Local<String> string;
  1061→      if (!value->ToString(env()->isolate()->GetCurrentContext())
  1062→               .ToLocal(&string))
  1063→        return Nothing<int>();
  1064→      js_array
  1065→          ->Set(context,
  1066→                i,
  1067→                string)
  1068→          .Check();
  1069→    }
  1070→
  1071→    Maybe<size_t> maybe_size = StringBytes::StorageSize(isolate, value, UTF8);
  1072→    if (maybe_size.IsNothing()) return Nothing<int>();
  1073→    data_size += maybe_size.FromJust() + 1;
  1074→    data_size = nbytes::RoundUp(data_size, sizeof(void*));
  1075→  }
  1076→
  1077→  buffer = new char[list_size + data_size];
  1078→
  1079→  list = reinterpret_cast<char**>(buffer);
  1080→  data_offset = list_size;
  1081→
  1082→  for (uint32_t i = 0; i < length; i++) {
  1083→    list[i] = buffer + data_offset;
  1084→    auto value = js_array->Get(context, i).ToLocalChecked();
  1085→    data_offset += StringBytes::Write(isolate,
  1086→                                      buffer + data_offset,
  1087→                                      -1,
  1088→                                      value,
  1089→                                      UTF8);
  1090→    buffer[data_offset++] = '\0';
  1091→    data_offset = nbytes::RoundUp(data_offset, sizeof(void*));
  1092→  }
  1093→
  1094→  list[length] = nullptr;
  1095→
  1096→  *target = buffer;
  1097→  return Just(0);
